export function NumbersDataImportTab() {
  const [isImporting, setIsImporting] = useState(false);
  const [importResult, setImportResult] = useState<ImportResult | null>(null);

  const runImport = async () => {
    setIsImporting(true);
    setImportResult(null);

    try {
      console.log('Starting import of', PARTICIPANT_DATA.length, 'participants');
      
      const response = await supabase.functions.invoke('import-participants', {
        body: { participants: PARTICIPANT_DATA }
      });

      if (response.error) {
        throw new Error(response.error.message);
      }

      const result = response.data as ImportResult;
      setImportResult(result);
      
      if (result.errors.length === 0) {
        toast.success(`Import fullført! ${result.updated} oppdatert, ${result.activitiesAdded} aktiviteter lagt til`);
      } else {
        toast.warning(`Import delvis fullført med ${result.errors.length} feil`);
      }
    } catch (error) {
      console.error('Import error:', error);
      toast.error('Kunne ikke importere data');
    } finally {
      setIsImporting(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <FileSpreadsheet className="w-5 h-5" />
          Importer fra Numbers-fil
        </CardTitle>
        <CardDescription>
          Oppdater {PARTICIPANT_DATA.length} deltakere med bilder, aktiviteter og ankomststatus
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="p-4 rounded-lg bg-muted/50 space-y-2">
          <div className="flex items-center gap-2 text-sm">
            <Users className="w-4 h-4" />
            <span className="font-medium">{PARTICIPANT_DATA.length} deltakere</span>
          </div>
          <div className="flex items-center gap-2 text-sm">
            <Activity className="w-4 h-4" />
            <span>Inkluderer: bilder, fødselsdato, hytte, ankomst, aktiviteter</span>
          </div>
        </div>

        <Button 
          onClick={runImport}
          disabled={isImporting}
          size="lg"
          className="w-full"
        >
          {isImporting ? (
            <>
              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
              Importerer...
            </>
          ) : (
            <>
              <Upload className="w-4 h-4 mr-2" />
              Start import
            </>
          )}
        </Button>

        {/* Import Result */}
        {importResult && (
          <div className={`p-4 rounded-lg ${importResult.errors.length > 0 ? 'bg-yellow-500/10 border border-yellow-500/20' : 'bg-green-500/10 border border-green-500/20'}`}>
            <div className="flex items-center gap-2 mb-2">
              <CheckCircle2 className="w-5 h-5 text-green-500" />
              <span className="font-medium">
                {importResult.updated} deltakere oppdatert
              </span>
            </div>
            <div className="text-sm text-muted-foreground space-y-1">
              <p>{importResult.activitiesAdded} aktiviteter lagt til</p>
              {importResult.notFound > 0 && (
                <p className="text-yellow-600 dark:text-yellow-400">
                  {importResult.notFound} deltakere ikke funnet i databasen
                </p>
              )}
            </div>
            {importResult.errors.length > 0 && (
              <div className="mt-3">
                <p className="text-sm font-medium text-red-600 dark:text-red-400">
                  Feil ({importResult.errors.length}):
                </p>
                <ul className="text-sm text-red-600 dark:text-red-400 list-disc list-inside max-h-32 overflow-y-auto">
                  {importResult.errors.slice(0, 10).map((error, idx) => (
                    <li key={idx}>{error}</li>
                  ))}
                  {importResult.errors.length > 10 && (
                    <li>...og {importResult.errors.length - 10} flere</li>
                  )}
                </ul>
              </div>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}
